(ProNom like &ProNom) or (ProGraBar like &ProNom) or (ProGraRef like &ProNom) or (ProBarRef_Comp like '%'+&ProNom)  or (ProNomApl like '%'+&ProNom) when not &ProNom.IsEmpty();
