TabPrc1 > &TabPrc12 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'TABPRC1' AND &DynamicFiltersOperator2 = 2 AND (not &TabPrc12.IsEmpty());
ProDtaCad >= &ProDtaCad2 when &DynamicFiltersEnabled2 AND &DynamicFiltersSelector2 = !'PRODTACAD' AND (not &ProDtaCad2.IsEmpty());
MarNom like &MarNom3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'MARNOM' AND (not &MarNom3.IsEmpty());
