TabPrc1 > &TabPrc13 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'TABPRC1' AND &DynamicFiltersOperator3 = 2 AND (not &TabPrc13.IsEmpty());
ProDtaCad >= &ProDtaCad3 when &DynamicFiltersEnabled3 AND &DynamicFiltersSelector3 = !'PRODTACAD' AND (not &ProDtaCad3.IsEmpty());
